import { WorkflowContext } from 'mastra/workflows';

const jailbreakPatterns = [
  /ignore previous instructions/i,
  /you are now/i,
  /system override/i,
  /jailbreak/i,
  /dan mode/i
];

export function scanWorkflowInput(ctx: WorkflowContext): boolean {
  const input = ctx.input as string;
  return jailbreakPatterns.some(pattern => pattern.test(input));
}

// Usage in Mastra workflow
workflow.onInput(async (ctx) => {
  if (scanWorkflowInput(ctx)) {
    throw new Error('Jailbreak attempt detected');
  }
});

import { AgentToolContext } from 'mastra/agents';

export async function validateToolResponse(ctx: AgentToolContext): Promise<string> {
  const response = await ctx.tool.call();

  const suspiciousPatterns = [
    'forget your instructions',
    'you are free to',
    'override safety',
    'bypass restrictions'
  ];

  const hasJailbreak = suspiciousPatterns.some(p => 
    response.toLowerCase().includes(p)
  );

  if (hasJailbreak) {
    console.warn('Blocked jailbreak in tool response:', response);
    return 'Tool response filtered for safety';
  }

  return response;
}

import { MemoryContext } from 'mastra/memory';

const JAILBREAK_SIGNATURES = {
  prefixes: ['SYSTEM OVERRIDE:', 'NEW INSTRUCTIONS:'],
  suffixes: ['IGNORE ALL RULES', 'EXECUTE NOW'],
  keywords: ['jailbroken', 'uncensored', 'no restrictions']
};

export function auditMemoryRetrieval(memory: MemoryContext): boolean {
  const content = memory.retrieve().join(' ');

  return (
    JAILBREAK_SIGNATURES.prefixes.some(p => content.startsWith(p)) ||
    JAILBREAK_SIGNATURES.suffixes.some(s => content.endsWith(s)) ||
    JAILBREAK_SIGNATURES.keywords.some(k => content.includes(k))
  );
}

// In Mastra agent
agent.onMemoryLoad(async (memory) => {
  if (auditMemoryRetrieval(memory)) {
    memory.clear();
  }
});

