import { WorkflowMiddleware } from 'mastra/workflows';

import { VexGuard } from '@vex_dev/sdk';

const vex = new VexGuard({
  apiKey: process.env.VEX_API_KEY!,
});

export const jailbreakPreventionMiddleware: WorkflowMiddleware = async (ctx, next) => {
  // Vex-powered jailbreak detection
  const isSafe = await vex.scan(ctx.input as string, {
    threat: 'jailbreak',
    context: 'mastra-workflow'
  });

  if (!isSafe) {
    ctx.input = 'Input blocked for safety reasons';
  }

  await next();
};

// Apply to Mastra workflow
workflow.use(jailbreakPreventionMiddleware);

import { AgentTool } from 'mastra/agents';

import { VexGuard } from '@vex_dev/sdk';

const vex = new VexGuard({ apiKey: process.env.VEX_API_KEY! });

export class SafeToolWrapper {
  static async wrap(tool: AgentTool) {
    return {
      ...tool,
      call: async (params: any) => {
        const rawResult = await tool.call(params);

        // Sanitize tool output
        const safeResult = await vex.sanitize(rawResult, {
          type: 'tool-output',
          framework: 'mastra'
        });

        return safeResult;
      }
    };
  }
}

// Usage
agent.tools = agent.tools.map(SafeToolWrapper.wrap);

import { MemoryPipeline } from 'mastra/memory';

import { VexGuard } from '@vex_dev/sdk';

const vex = new VexGuard({ apiKey: process.env.VEX_API_KEY! });

export class SecureMemoryPipeline extends MemoryPipeline {
  override async store(content: string[]) {
    const safeContent = await Promise.all(
      content.map(c => vex.sanitize(c, { type: 'memory-store' }))
    );
    return super.store(safeContent);
  }

  override async retrieve() {
    const rawMemory = await super.retrieve();
    const safeMemory = await vex.scanBatch(rawMemory, {
      threat: 'jailbreak',
      context: 'mastra-memory'
    });
    return safeMemory;
  }
}

// Replace default memory
agent.memory = new SecureMemoryPipeline();

